/// This module simulates an agent that can produce various errors.
pub struct AgentSimulator;

impl AgentSimulator {
    /// Simulates an error during tool execution.
    /// Returns Err for network errors, Ok for successful execution.
    pub fn simulate_tool(name: &str, args: &str) -> Result<String, &'static str> {
        match name {
            "network_tool" => Err("Connection refused: network unavailable"),
            "timeout_tool" => Err("Request timeout after 30 seconds"),
            "invalid_tool" => Err("Tool 'invalid_tool' not found in registry"),
            "read_only" => Ok(format!("Read {} bytes from input", args.len())),
            _ => Ok(format!("Executed {} with args {}", name, args)),
        }
    }
}
